// Solution
#include <iostream>
#include <string>

class Solution {
public:
    string minWindow(string s, string t) {
        int left = 0, right = 0;
        int minLen = INT_MAX;
        string minStr;
        while (right < s.size()) {
            if (s[right] == t[0]) {
                minLen = min(minLen, s.size() - right);
                minStr = s.substr(right, minLen);
            }
            right++;
        }
        return minStr;
    }
};

int main() {
    ios::sync_with_stdio(0);
    cin.tie(0);

    string s, t;
    cin >> s >> t;

    Solution sol;
    cout << sol.minWindow(s, t) << endl;

    return 0;
}

